
class ComponentStatus {final String apiVersion; final String kind; final ObjectMeta metadata; final List<ComponentCondition>? conditions; ComponentStatus({this.apiVersion = 'v1', this.kind = 'ComponentStatus', required this.metadata, this.conditions}); factory ComponentStatus.fromJson(Map<String, dynamic> json) {return ComponentStatus(apiVersion: json['apiVersion'] ?? 'v1', kind: json['kind'] ?? 'ComponentStatus', metadata: ObjectMeta.fromJson(json['metadata']), conditions: json['conditions'] != null ? (json['conditions'] as List).map((e) => ComponentCondition.fromJson(e)).toList() : null);} Map<String, dynamic> toJson() {return {'apiVersion' : apiVersion, 'kind' : kind, 'metadata' : metadata.toJson(), if (conditions != null) 'conditions' : conditions!.map((e) => e.toJson()).toList()};}}
